/*
Your task is to write a function that returns true if a number x is a simple
power of n && false in other cases.
x is a simple power of n if n**int=x
For example:
p076_is_simple_power(1, 4) => true
p076_is_simple_power(2, 2) => true
p076_is_simple_power(8, 2) => true
p076_is_simple_power(3, 2) => false
p076_is_simple_power(3, 1) => false
p076_is_simple_power(5, 3) => false
*/
#include "verification_stdlib.h"
/*@ Extern Coq (problem_76_pre: Z -> Z -> Prop) */
/*@ Extern Coq (is_simple_power_spec: Z -> Z -> Z -> Prop) */
/*@ Extern Coq (sp_inv: Z -> Z -> Z -> Z -> Prop) */
/*@ Import Coq Require Import p076_is_simple_power */
int p076_is_simple_power(int x, int n)
/*@ Require
        1 <= x && x <= INT_MAX &&
        1 <= n && n <= INT_MAX &&
        x * n <= INT_MAX && emp
    Ensure
        is_simple_power_spec(x@pre, n@pre, __return) && emp
*/
{
    int p=1,count=0;

    /*@ Inv Assert
          x == x@pre && n == n@pre &&
          1 <= x && x <= INT_MAX &&
          1 <= n && n <= INT_MAX &&
          x * n <= INT_MAX &&
          0 <= count && count <= 100 &&
          sp_inv(x, n, count, p) &&
          1 <= p && p <= x * n
    */
    while (p<=x && count<100)
    {
        if (p==x) return 1;
        /*@ Assert
              p < x &&
              0 <= count && count < 100 &&
              x == x@pre && n == n@pre &&
              1 <= p && 1 <= x &&
              1 <= n && n <= INT_MAX &&
              x <= INT_MAX &&
              x * n <= INT_MAX &&
              sp_inv(x, n, count, p) &&
              p <= x * n &&
              p * n <= INT_MAX
        */
        p = p * n;
        /*@ Assert exists c,
              count == c &&
              x == x@pre && n == n@pre &&
              1 <= x && x <= INT_MAX &&
              1 <= n && n <= INT_MAX &&
              x * n <= INT_MAX &&
              0 <= c && c < 100 &&
              sp_inv(x, n, c + 1, p) &&
              1 <= p && p <= x * n
        */
        count += 1;
    }
    return 0;
}

/*@ Extern Coq (sum : list Z -> Z)
               (zeros: Z -> list Z)
*/

int arr_sum(int n, int *a)
/*@ With l
    Require 0 < n && n < 100 && IntArray::full(a, n, l) && (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100))
    Ensure  __return == sum(l) && IntArray::full(a, n, l) 
*/
{
  int i;
  i = 0;
  int ret;
  ret = 0;
  /*@ Inv
      0 <= i && i <= n && n == n@pre && ret == sum(sublist(0, i, l))
  */
  while (i < n) {
    ret += a[i];
    ++i;
  }
  return ret;
}

int arr_sum_do_while(int n, int *a)
/*@ With l
    Require 0 < n && n < 100 && IntArray::full(a, n, l) && (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100))
    Ensure  __return == sum(l) && IntArray::full(a, n, l)
*/
{
  int i = 0;
  int ret = 0;
  do {
    ret += a[i];
    ++i;
  } /*@ Inv 0 <= i && i <= n && n == n@pre && ret == sum(sublist(0, i, l)) */ while (i != n);
  return ret;
}

int arr_sum_for(int n, int *a)
/*@ With l
    Require 0 < n && n < 100 && IntArray::full(a, n, l) && (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100))
    Ensure  __return == sum(l) && IntArray::full(a, n, l)
*/
{
  int i;
  int ret = 0;
  /*@ Inv
      0 <= i && i <= n && n == n@pre && ret == sum(sublist(0, i, l))
  */
  for (i = 0; i < n; ++i) {
    ret += a[i];
  }
  return ret;
}

int arr_sum_which_implies(int n, int *a)
/*@ With l
    Require 0 < n && n < 100 && (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100)) && IntArray::full(a, n, l)
    Ensure  __return == sum(l) && IntArray::full(a, n, l)
*/
{
  int i;
  int ret = 0;
  /*@ Inv
      0 <= i && i <= n@pre && ret == sum(sublist(0, i, l))
  */
  for (i = 0; i < n; ++i) {
    /*@ 0 <= i && i < n@pre && IntArray::full(a, n@pre, l) 
        which implies
        store(a + (i * sizeof(int)), int, l[i]) * IntArray::missing_i(a, i, 0, n@pre, l)
    */
    ret += a[i];
    /*@ 0 <= i && i < n@pre && store(a + (i * sizeof(int)), int, l[i]) * IntArray::missing_i(a, i, 0, n@pre, l)
        which implies
        0<= i && i < n@pre && IntArray::full(a, n@pre, l)
    */
  }
  return ret;
}

int arr_sum_update(int n, int *a)
/*@ With l
    Require 0 < n && n < 100 && (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100)) && IntArray::full(a, n, l)
    Ensure  __return == sum(l) && IntArray::full(a, n, zeros(n))
*/
{
  int i;
  int ret = 0;
  /*@ Inv 
      0 <= i && i <= n@pre && n@pre == Zlength(l) && ret == sum(sublist(0, i, l)) && a == a@pre &&
      IntArray::full(a, n@pre, app(zeros(i), sublist(i, n@pre, l)))
  */
  for (i = 0; i < n; ++i) {
    /*@ 0 <= i && i < n@pre && a == a@pre && n@pre == Zlength(l) && IntArray::full(a, n@pre, app(zeros(i), sublist(i, n@pre, l))) 
        which implies
        a == a@pre && IntArray::missing_i(a, i, 0, n@pre, app(zeros(i), sublist(i, n@pre, l))) * store(a + (i * sizeof(int)), int, l[i])
    */
    ret += a[i];
    a[i] = 0;
    /*@ 0 <= i && i < n@pre && a == a@pre && n@pre == Zlength(l) && IntArray::missing_i(a, i, 0, n@pre, app(zeros(i), sublist(i, n@pre, l))) * store(a + (i * sizeof(int)), int, 0)
        which implies
        a == a@pre && IntArray::full(a, n@pre, app(zeros(i + 1), sublist(i + 1, n@pre, l)))
    */
  }
  return ret;
}


int arr_sum_pointer(int n, int *a)
/*@ With l
    Require 0 < n && n < 100 && IntArray::full(a, n, l) && (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100))
    Ensure  __return == sum(l) && IntArray::full(a, n, l)
*/
{
  int i = 0;
  int ret = 0;
  int *endp = a + n;
  /*@ Inv
      0 <= i && i <= n && n == n@pre && ret == sum(sublist(0, i, l)) */
  while (endp - (a + i) != 0) {
    /*@ i != n */
    ret += *(a + i);
    ++i;
  }
  return ret;
}

/*@ Extern Coq (IsMajorityElement : Z -> list Z -> Prop) */
/*@ Extern Coq (MajorityOnReduced : Z -> Z -> Z -> list Z -> Prop) */

/*@ Import Coq Require Import SimpleC.EE.QCP_demos_human.majorityElement_lib */

int majorityElement(int* nums, int numsSize)
/*@ With (l : list Z)
    Require exists x, IsMajorityElement(x,l) && 1 <= numsSize && numsSize <= 50000 && Zlength(l) == numsSize && IntArray::full(nums, numsSize, l)
    Ensure IsMajorityElement(__return, l) && IntArray::full(nums, numsSize, l)
*/
{
    int vote = 0;
    int candidate = 0;
    /*@ Inv Assert
        exists x l1 l2,
            nums == nums@pre && numsSize == numsSize@pre &&
            l == app(l1, l2) &&
            i == Zlength(l1) &&
            0 <= i && i <= numsSize &&
            1 <= numsSize && numsSize <= 50000 &&
            0 <= vote && vote <= i &&
            IsMajorityElement(x, l) &&
            MajorityOnReduced(x, candidate, vote, l2) &&
            IntArray::full(nums, numsSize, l)
    */
    for (int i = 0; i < numsSize; i++) {
        if (vote == 0) {
            candidate = nums[i];
        }
        vote += (nums[i] == candidate) ? 1 : -1;
    }
    return candidate;
}

